parameters.jsCode:
const items = $input.all();
const roles = ['CMO (Marketing)', 'CFO (Finance)', 'COO (Operations)', 'CPO (Product)', 'CLO (Legal)'];
const opinions = items.map((item, i) => {
  const role = roles[i] || `Director ${i+1}`;
  const output = item.json.output || '';
  return `## ${role}\n\n${output}`;
});
return [{ json: { bod_opinions: opinions.join('\n\n---\n\n') } }];
